"""Protein substitution models and maximum-likelihood distance estimation.

Amino acid order (ARNDCQEGHILKMFPSTWYV) matches WAG/JTT/LG convention.
Models ported from the modelmatcher package.
"""

from __future__ import annotations

import numpy as np

from . import _fastphylo

# Standard amino acid alphabet (20 canonical residues)
AA_ORDER = "ARNDCQEGHILKMFPSTWYV"


# ---------------------------------------------------------------------------
# RateMatrix base class
# ---------------------------------------------------------------------------

class RateMatrix:
    """Protein substitution rate matrix with Q-matrix and eigen decomposition."""

    def __init__(self, name: str) -> None:
        self.name = name
        self.R: np.ndarray | None = None
        self.Q: np.ndarray | None = None
        self.freq: np.ndarray | None = None
        self.right_eigenvectors: np.ndarray | None = None
        self.left_eigenvectors: np.ndarray | None = None
        self.q_eigenvals: np.ndarray | None = None

    @classmethod
    def instantiate(cls, modelname: str) -> "RateMatrix":
        registry = {c.__name__: c for c in cls.__subclasses__()}
        # Also index by the name attribute (for models with non-class names)
        for c in cls.__subclasses__():
            inst = c.__new__(c)
            inst.name = ""
        if modelname in registry:
            return registry[modelname]()
        # Try case-insensitive match
        lower = {k.lower(): v for k, v in registry.items()}
        if modelname.lower() in lower:
            return lower[modelname.lower()]()
        available = sorted(registry)
        raise ValueError(
            f"Unknown protein model {modelname!r}. "
            f"Available: {', '.join(available)}"
        )

    @classmethod
    def all_models(cls) -> list[str]:
        return sorted(c.__name__ for c in cls.__subclasses__())

    def set_r_and_freq(self, r_elems: list[float], freq: list[float]) -> None:
        R = np.zeros((20, 20))
        xs, ys = np.tril_indices(20, k=-1)
        R[xs, ys] = r_elems
        R[ys, xs] = r_elems
        self.R = R
        self.update_freq(freq)

    def update_freq(self, freq: list[float] | np.ndarray) -> None:
        self.freq = np.array(freq)
        D_freq = np.diag(self.freq)
        Q = np.matmul(self.R, D_freq)
        Q[np.diag_indices(20)] = -np.sum(Q, axis=1)
        scale = -np.sum(D_freq * Q.diagonal(0))
        self.Q = Q / scale
        self._init_decomposition()

    def _init_decomposition(self) -> None:
        # Symmetrise Q so eigendecomposition is real: S = D^(1/2) Q D^(-1/2)
        sqrt_freq = np.sqrt(self.freq)
        inv_sqrt_freq = 1.0 / sqrt_freq
        S = sqrt_freq[:, None] * self.Q * inv_sqrt_freq[None, :]
        evals, U = np.linalg.eigh(S)           # real eigenvalues guaranteed
        self.q_eigenvals = evals
        self.right_eigenvectors = U * inv_sqrt_freq[:, None]   # D^(-1/2) U
        self.left_eigenvectors  = (U * sqrt_freq[:, None]).T   # U^T D^(1/2)

    def get_replacement_probs(self, t: float) -> np.ndarray:
        exp_ev = np.exp(self.q_eigenvals * t)
        # R @ diag(exp_ev) @ L: scale columns of R, then multiply by L
        return (self.right_eigenvectors * exp_ev) @ self.left_eigenvectors


